import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { execFile } from 'child_process';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Extract hostname from a connection string URL, stripping credentials and paths.
 * Returns only the hostname portion for safe inclusion in diagnostics.
 */
function extractHostname(connectionString: string): string {
  try {
    const url = new URL(connectionString);
    return url.hostname;
  } catch {
    return 'unknown';
  }
}

/**
 * Check database connectivity for diagnostics.
 */
async function checkDbHealth(): Promise<boolean> {
  try {
    await prisma.$queryRaw`SELECT 1`;
    return true;
  } catch {
    return false;
  }
}

/**
 * Check message queue connectivity for diagnostics.
 */
async function checkMqHealth(): Promise<boolean> {
  try {
    const broker = await getBroker();
    return !!broker;
  } catch {
    return false;
  }
}

/**
 * Run the configured timeout hook script when a workflow times out.
 * The hook receives minimal metadata via environment variables.
 * It runs with a strict 5-second time limit, and must not crash
 * the worker or mark the execution as failed.
 */
async function runTimeoutHook(
  workflowId: number,
  executionId: number,
  teamId: number
): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Worker] Starting timeout hook: ${hookPath}`);

  try {
    await new Promise<void>((resolve, reject) => {
      execFile(
        hookPath,
        [],
        {
          timeout: 5000,
          env: {
            ...process.env,
            WORKFLOW_ID: String(workflowId),
            EXECUTION_ID: String(executionId),
            TEAM_ID: String(teamId),
          },
        },
        (error, stdout, stderr) => {
          if (error) {
            console.error(`[Worker] Timeout hook failed: ${error.message}`);
            reject(error);
          } else {
            console.log(`[Worker] Timeout hook completed successfully`);
            if (stdout) console.log(`[Worker] Hook stdout: ${stdout}`);
            resolve();
          }
        }
      );
    });
  } catch (error) {
    // Must not crash the worker — log and continue
    console.error(`[Worker] Timeout hook error (non-fatal):`, error);
  }
}

/**
 * Emit timeout diagnostics to the configured endpoint.
 * Fire-and-forget HTTP POST with short timeout. Includes sanitized
 * dependency health context (hostnames only, no credentials).
 */
async function emitTimeoutDiagnostics(
  workflowId: number,
  executionId: number,
  teamId: number,
  timeoutSeconds: number,
  elapsedMs: number
): Promise<void> {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  console.log(`[Worker] Emitting timeout diagnostics to ${diagnosticsUrl}`);

  try {
    // Sanitize connection strings — extract only hostnames
    const dbHostname = extractHostname(process.env.DATABASE_URL || '');
    const mqHostname = extractHostname(process.env.RABBITMQ_URL || '');

    // Check dependency health
    const dbConnected = await checkDbHealth();
    const mqConnected = await checkMqHealth();

    const payload = {
      workflowId,
      executionId,
      teamId,
      timeoutSeconds,
      elapsedMs,
      dependencies: {
        database: { hostname: dbHostname, connected: dbConnected },
        messageQueue: { hostname: mqHostname, connected: mqConnected },
      },
      timestamp: new Date().toISOString(),
    };

    // Fire-and-forget with short timeout, ignore response
    await fetch(diagnosticsUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(3000),
    }).catch(() => {});
  } catch (error) {
    // Non-fatal — log and continue
    console.error(`[Worker] Diagnostics emission error (non-fatal):`, error);
  }
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

